   107→  // Merge in the headers.
   108→  if (request_headers.EnvoyRetryOn()) {
   109→    retry_on_ |= parseRetryOn(request_headers.getEnvoyRetryOnValue()).first;
   110→  }
   111→  if (request_headers.EnvoyRetryGrpcOn()) {
   112→    retry_on_ |= parseRetryGrpcOn(request_headers.getEnvoyRetryGrpcOnValue()).first;
   113→  }
   114→
   115→  const auto& retriable_request_headers = route_policy.retriableRequestHeaders();
   116→  if (!retriable_request_headers.empty()) {
   117→    // If this route limits retries by request headers, make sure there is a match.
   118→    bool request_header_match = false;
   119→    for (const auto& retriable_header : retriable_request_headers) {
   120→      if (retriable_header->matchesHeaders(request_headers)) {
   121→        request_header_match = true;
   122→        break;
   123→      }
   124→    }
   125→
   126→    if (!request_header_match) {
   127→      retry_on_ = 0;
   128→    }
   129→  }
   130→  if (retry_on_ != 0 && request_headers.EnvoyMaxRetries()) {
   131→    uint64_t temp;
   132→    if (absl::SimpleAtoi(request_headers.getEnvoyMaxRetriesValue(), &temp)) {
   133→      // The max retries header takes precedence if set.
   134→      retries_remaining_ = temp;
   135→    }
   136→  }
   137→
   138→  if (request_headers.EnvoyRetriableStatusCodes()) {
   139→    for (const auto& code :
   140→         StringUtil::splitToken(request_headers.getEnvoyRetriableStatusCodesValue(), ",")) {
   141→      unsigned int out;
   142→      if (absl::SimpleAtoi(code, &out)) {
   143→        retriable_status_codes_.emplace_back(out);
   144→      }
   145→    }
   146→  }
   147→
   148→  if (request_headers.EnvoyRetriableHeaderNames()) {
   149→    // Retriable headers in the configuration are specified via HeaderMatcher.
   150→    // Giving the same flexibility via request header would require the user
   151→    // to provide HeaderMatcher serialized into a string. To avoid this extra
   152→    // complexity we only support name-only header matchers via request
   153→    // header. Anything more sophisticated needs to be provided via config.
   154→    for (const auto& header_name : StringUtil::splitToken(
   155→             request_headers.EnvoyRetriableHeaderNames()->value().getStringView(), ",")) {
   156→      envoy::config::route::v3::HeaderMatcher header_matcher;
   157→      header_matcher.set_name(std::string(absl::StripAsciiWhitespace(header_name)));
   158→      retriable_headers_.emplace_back(
   159→          Http::HeaderUtility::createHeaderData(header_matcher, context));
   160→    }
   161→  }
   162→}
   163→
   164→RetryStateImpl::~RetryStateImpl() { resetRetry(); }
   165→
   166→void RetryStateImpl::enableBackoffTimer() {
   167→  if (!retry_timer_) {
   168→    retry_timer_ = dispatcher_.createTimer([this]() -> void { backoff_callback_(); });
   169→  }
   170→
   171→  if (ratelimited_backoff_strategy_ != nullptr) {
   172→    // If we have a backoff strategy based on rate limit feedback from the response we use it.
   173→    retry_timer_->enableTimer(
   174→        std::chrono::milliseconds(ratelimited_backoff_strategy_->nextBackOffMs()));
   175→
   176→    // The strategy is only valid for the response that sent the ratelimit reset header and cannot
   177→    // be reused.
   178→    ratelimited_backoff_strategy_.reset();
   179→
   180→    cluster_.trafficStats()->upstream_rq_retry_backoff_ratelimited_.inc();
   181→
   182→  } else {
   183→    // Otherwise we use a fully jittered exponential backoff algorithm.
   184→    retry_timer_->enableTimer(std::chrono::milliseconds(backoff_strategy_->nextBackOffMs()));
   185→
   186→    cluster_.trafficStats()->upstream_rq_retry_backoff_exponential_.inc();
   187→  }
   188→}
   189→
   190→std::pair<uint32_t, bool> RetryStateImpl::parseRetryOn(absl::string_view config) {
   191→  uint32_t ret = 0;
   192→  bool all_fields_valid = true;
   193→  for (const auto& retry_on : StringUtil::splitToken(config, ",", false, true)) {
   194→    if (retry_on == Http::Headers::get().EnvoyRetryOnValues._5xx) {
   195→      ret |= RetryPolicy::RETRY_ON_5XX;
   196→    } else if (retry_on == Http::Headers::get().EnvoyRetryOnValues.GatewayError) {
   197→      ret |= RetryPolicy::RETRY_ON_GATEWAY_ERROR;
   198→    } else if (retry_on == Http::Headers::get().EnvoyRetryOnValues.ConnectFailure) {
   199→      ret |= RetryPolicy::RETRY_ON_CONNECT_FAILURE;
   200→    } else if (retry_on == Http::Headers::get().EnvoyRetryOnValues.EnvoyRateLimited) {
   201→      ret |= RetryPolicy::RETRY_ON_ENVOY_RATE_LIMITED;
   202→    } else if (retry_on == Http::Headers::get().EnvoyRetryOnValues.Retriable4xx) {
   203→      ret |= RetryPolicy::RETRY_ON_RETRIABLE_4XX;
   204→    } else if (retry_on == Http::Headers::get().EnvoyRetryOnValues.RefusedStream) {
   205→      ret |= RetryPolicy::RETRY_ON_REFUSED_STREAM;
   206→    } else if (retry_on == Http::Headers::get().EnvoyRetryOnValues.RetriableStatusCodes) {
   207→      ret |= RetryPolicy::RETRY_ON_RETRIABLE_STATUS_CODES;
   208→    } else if (retry_on == Http::Headers::get().EnvoyRetryOnValues.RetriableHeaders) {
   209→      ret |= RetryPolicy::RETRY_ON_RETRIABLE_HEADERS;
   210→    } else if (retry_on == Http::Headers::get().EnvoyRetryOnValues.Reset) {
   211→      ret |= RetryPolicy::RETRY_ON_RESET;
   212→    } else if (retry_on == Http::Headers::get().EnvoyRetryOnValues.ResetBeforeRequest) {
   213→      ret |= RetryPolicy::RETRY_ON_RESET_BEFORE_REQUEST;
   214→    } else if (retry_on == Http::Headers::get().EnvoyRetryOnValues.Http3PostConnectFailure) {
   215→      ret |= RetryPolicy::RETRY_ON_HTTP3_POST_CONNECT_FAILURE;
   216→    } else {
   217→      all_fields_valid = false;
   218→    }
   219→  }
   220→
   221→  return {ret, all_fields_valid};
   222→}
   223→
   224→std::pair<uint32_t, bool> RetryStateImpl::parseRetryGrpcOn(absl::string_view retry_grpc_on_header) {
   225→  uint32_t ret = 0;
   226→  bool all_fields_valid = true;
   227→  for (const auto& retry_on : StringUtil::splitToken(retry_grpc_on_header, ",", false, true)) {
   228→    if (retry_on == Http::Headers::get().EnvoyRetryOnGrpcValues.Cancelled) {
   229→      ret |= RetryPolicy::RETRY_ON_GRPC_CANCELLED;
   230→    } else if (retry_on == Http::Headers::get().EnvoyRetryOnGrpcValues.DeadlineExceeded) {
   231→      ret |= RetryPolicy::RETRY_ON_GRPC_DEADLINE_EXCEEDED;
   232→    } else if (retry_on == Http::Headers::get().EnvoyRetryOnGrpcValues.ResourceExhausted) {
   233→      ret |= RetryPolicy::RETRY_ON_GRPC_RESOURCE_EXHAUSTED;
   234→    } else if (retry_on == Http::Headers::get().EnvoyRetryOnGrpcValues.Unavailable) {
   235→      ret |= RetryPolicy::RETRY_ON_GRPC_UNAVAILABLE;
   236→    } else if (retry_on == Http::Headers::get().EnvoyRetryOnGrpcValues.Internal) {
   237→      ret |= RetryPolicy::RETRY_ON_GRPC_INTERNAL;
   238→    } else {
   239→      all_fields_valid = false;
   240→    }
   241→  }
   242→
   243→  return {ret, all_fields_valid};
   244→}
   245→
   246→absl::optional<std::chrono::milliseconds>
   247→RetryStateImpl::parseResetInterval(const Http::ResponseHeaderMap& response_headers) const {
   248→  for (const auto& reset_header : reset_headers_) {
   249→    const auto& interval = reset_header->parseInterval(time_source_, response_headers);
   250→    if (interval.has_value() && interval.value() <= reset_max_interval_) {
   251→      return interval;
   252→    }
   253→  }
   254→
   255→  return absl::nullopt;
   256→}
   257→
   258→void RetryStateImpl::resetRetry() {
   259→  if (backoff_callback_ != nullptr) {
   260→    cluster_.resourceManager(priority_).retries().dec();
   261→    backoff_callback_ = nullptr;
   262→  }
   263→  if (next_loop_callback_ != nullptr) {
   264→    cluster_.resourceManager(priority_).retries().dec();
   265→    next_loop_callback_ = nullptr;
   266→  }
   267→}
   268→
   269→RetryStatus RetryStateImpl::shouldRetry(RetryDecision would_retry, DoRetryCallback callback) {
   270→  // If a callback is armed from a previous shouldRetry and we don't need to
   271→  // retry this particular request, we can infer that we did a retry earlier
   272→  // and it was successful.
   273→  if ((backoff_callback_ || next_loop_callback_) && would_retry == RetryDecision::NoRetry) {
   274→    cluster_.trafficStats()->upstream_rq_retry_success_.inc();
   275→    if (vcluster_) {
   276→      vcluster_->stats().upstream_rq_retry_success_.inc();
   277→    }
   278→    if (route_stats_context_.has_value()) {
   279→      route_stats_context_->stats().upstream_rq_retry_success_.inc();
   280→    }
   281→  }
   282→
   283→  resetRetry();
   284→
   285→  if (would_retry == RetryDecision::NoRetry) {
   286→    return RetryStatus::No;
   287→  }
   288→
   289→  // The request has exhausted the number of retries allotted to it by the retry policy configured
   290→  // (or the x-envoy-max-retries header).
   291→  if (retries_remaining_ == 0) {
   292→    cluster_.trafficStats()->upstream_rq_retry_limit_exceeded_.inc();
   293→    if (vcluster_) {
   294→      vcluster_->stats().upstream_rq_retry_limit_exceeded_.inc();
   295→    }
   296→    if (route_stats_context_.has_value()) {
   297→      route_stats_context_->stats().upstream_rq_retry_limit_exceeded_.inc();
   298→    }
   299→    return RetryStatus::NoRetryLimitExceeded;
   300→  }
   301→
   302→  retries_remaining_--;
   303→
   304→  if (!cluster_.resourceManager(priority_).retries().canCreate()) {
   305→    cluster_.trafficStats()->upstream_rq_retry_overflow_.inc();
   306→    if (vcluster_) {
   307→      vcluster_->stats().upstream_rq_retry_overflow_.inc();
   308→    }
   309→    if (route_stats_context_.has_value()) {
   310→      route_stats_context_->stats().upstream_rq_retry_overflow_.inc();
   311→    }
   312→    return RetryStatus::NoOverflow;
   313→  }
   314→
   315→  if (!runtime_.snapshot().featureEnabled("upstream.use_retry", 100)) {
   316→    return RetryStatus::No;
   317→  }
   318→
   319→  ASSERT(!backoff_callback_ && !next_loop_callback_);
   320→  cluster_.resourceManager(priority_).retries().inc();
   321→  cluster_.trafficStats()->upstream_rq_retry_.inc();
   322→  if (vcluster_) {
   323→    vcluster_->stats().upstream_rq_retry_.inc();
   324→  }
   325→  if (route_stats_context_.has_value()) {
   326→    route_stats_context_->stats().upstream_rq_retry_.inc();
   327→  }
   328→  if (would_retry == RetryDecision::RetryWithBackoff) {
   329→    backoff_callback_ = callback;
   330→    enableBackoffTimer();
   331→  } else {
   332→    next_loop_callback_ = dispatcher_.createSchedulableCallback(callback);
   333→    next_loop_callback_->scheduleCallbackNextIteration();
   334→  }
   335→  return RetryStatus::Yes;
   336→}
   337→
   338→RetryStatus RetryStateImpl::shouldRetryHeaders(const Http::ResponseHeaderMap& response_headers,
   339→                                               const Http::RequestHeaderMap& original_request,
   340→                                               DoRetryHeaderCallback callback) {
   341→  // This may be overridden in wouldRetryFromHeaders().
   342→  bool disable_early_data = false;
   343→  const RetryDecision retry_decision =
   344→      wouldRetryFromHeaders(response_headers, original_request, disable_early_data);
   345→
   346→  // Yes, we will retry based on the headers - try to parse a rate limited reset interval from the
   347→  // response.
   348→  if (retry_decision == RetryDecision::RetryWithBackoff && !reset_headers_.empty()) {
   349→    const auto backoff_interval = parseResetInterval(response_headers);
   350→    if (backoff_interval.has_value() && (backoff_interval.value().count() > 1L)) {
   351→      ratelimited_backoff_strategy_ = std::make_unique<JitteredLowerBoundBackOffStrategy>(
   352→          backoff_interval.value().count(), random_);
   353→    }
   354→  }
   355→
   356→  return shouldRetry(retry_decision,
   357→                     [disable_early_data, callback]() { callback(disable_early_data); });
   358→}
   359→
   360→RetryStatus RetryStateImpl::shouldRetryReset(Http::StreamResetReason reset_reason,
   361→                                             Http3Used http3_used, DoRetryResetCallback callback,
   362→                                             bool upstream_request_started) {
   363→
   364→  // Following wouldRetryFromReset() may override the value.
   365→  bool disable_http3 = false;
   366→  const RetryDecision retry_decision =
   367→      wouldRetryFromReset(reset_reason, http3_used, disable_http3, upstream_request_started);
   368→  return shouldRetry(retry_decision, [disable_http3, callback]() { callback(disable_http3); });
   369→}
   370→
   371→RetryStatus RetryStateImpl::shouldHedgeRetryPerTryTimeout(DoRetryCallback callback) {
   372→  // A hedged retry on per try timeout is always retried if there are retries
   373→  // left. NOTE: this is a bit different than non-hedged per try timeouts which
   374→  // are only retried if the applicable retry policy specifies either
   375→  // RETRY_ON_5XX or RETRY_ON_GATEWAY_ERROR. This is because these types of
   376→  // retries are associated with a stream reset which is analogous to a gateway
   377→  // error. When hedging on per try timeout is enabled, however, there is no
   378→  // stream reset.
   379→  return shouldRetry(RetryState::RetryDecision::RetryWithBackoff, callback);
   380→}
   381→
   382→RetryState::RetryDecision
   383→RetryStateImpl::wouldRetryFromHeaders(const Http::ResponseHeaderMap& response_headers,
   384→                                      const Http::RequestHeaderMap& original_request,
   385→                                      bool& disable_early_data) {
   386→  // A response that contains the x-envoy-ratelimited header comes from an upstream envoy.
   387→  // We retry these only when the envoy-ratelimited policy is in effect.
   388→  if (response_headers.EnvoyRateLimited() != nullptr) {
   389→    return (retry_on_ & RetryPolicy::RETRY_ON_ENVOY_RATE_LIMITED) ? RetryDecision::RetryWithBackoff
   390→                                                                  : RetryDecision::NoRetry;
   391→  }
   392→
   393→  uint64_t response_status = Http::Utility::getResponseStatus(response_headers);
   394→
   395→  if (retry_on_ & RetryPolicy::RETRY_ON_5XX) {
   396→    if (Http::CodeUtility::is5xx(response_status)) {
   397→      return RetryDecision::RetryWithBackoff;
   398→    }
   399→  }
   400→
   401→  if (retry_on_ & RetryPolicy::RETRY_ON_GATEWAY_ERROR) {
   402→    if (Http::CodeUtility::isGatewayError(response_status)) {
   403→      return RetryDecision::RetryWithBackoff;
   404→    }
   405→  }
   406→
   407→  if ((retry_on_ & RetryPolicy::RETRY_ON_RETRIABLE_4XX)) {
   408→    Http::Code code = static_cast<Http::Code>(response_status);
   409→    if (code == Http::Code::Conflict) {
   410→      return RetryDecision::RetryWithBackoff;
   411→    }
   412→  }
   413→
   414→  if ((retry_on_ & RetryPolicy::RETRY_ON_RETRIABLE_STATUS_CODES)) {
   415→    for (auto code : retriable_status_codes_) {
   416→      if (response_status == code) {
   417→        if (static_cast<Http::Code>(code) != Http::Code::TooEarly) {
   418→          return RetryDecision::RetryWithBackoff;
   419→        }
   420→        if (original_request.get(Http::Headers::get().EarlyData).empty()) {
   421→          // Retry if the downstream request wasn't received as early data. Otherwise, regardless if
   422→          // the request was sent as early data in upstream or not, don't retry. Instead, forward
   423→          // the response to downstream.
   424→          disable_early_data = true;
   425→          return RetryDecision::RetryImmediately;
   426→        }
   427→      }
   428→    }
   429→  }
   430→
   431→  if (retry_on_ & RetryPolicy::RETRY_ON_RETRIABLE_HEADERS) {
   432→    for (const auto& retriable_header : retriable_headers_) {
   433→      if (retriable_header->matchesHeaders(response_headers)) {
   434→        return RetryDecision::RetryWithBackoff;
   435→      }
   436→    }
   437→  }
   438→
   439→  if (retry_on_ &
   440→      (RetryPolicy::RETRY_ON_GRPC_CANCELLED | RetryPolicy::RETRY_ON_GRPC_DEADLINE_EXCEEDED |
   441→       RetryPolicy::RETRY_ON_GRPC_RESOURCE_EXHAUSTED | RetryPolicy::RETRY_ON_GRPC_UNAVAILABLE |
   442→       RetryPolicy::RETRY_ON_GRPC_INTERNAL)) {
   443→    absl::optional<Grpc::Status::GrpcStatus> status = Grpc::Common::getGrpcStatus(response_headers);
   444→    if (status) {
   445→      if ((status.value() == Grpc::Status::Canceled &&
   446→           (retry_on_ & RetryPolicy::RETRY_ON_GRPC_CANCELLED)) ||
   447→          (status.value() == Grpc::Status::DeadlineExceeded &&
   448→           (retry_on_ & RetryPolicy::RETRY_ON_GRPC_DEADLINE_EXCEEDED)) ||
   449→          (status.value() == Grpc::Status::ResourceExhausted &&
   450→           (retry_on_ & RetryPolicy::RETRY_ON_GRPC_RESOURCE_EXHAUSTED)) ||
   451→          (status.value() == Grpc::Status::Unavailable &&
   452→           (retry_on_ & RetryPolicy::RETRY_ON_GRPC_UNAVAILABLE)) ||
   453→          (status.value() == Grpc::Status::Internal &&
   454→           (retry_on_ & RetryPolicy::RETRY_ON_GRPC_INTERNAL))) {
   455→        return RetryDecision::RetryWithBackoff;
   456→      }
   457→    }
   458→  }
   459→
   460→  return RetryDecision::NoRetry;
   461→}
   462→
   463→RetryState::RetryDecision
   464→RetryStateImpl::wouldRetryFromReset(const Http::StreamResetReason reset_reason,
   465→                                    Http3Used http3_used, bool& disable_http3,
   466→                                    bool upstream_request_started) {
   467→  ASSERT(!disable_http3);
   468→  // First check "never retry" conditions so we can short circuit (we never
   469→  // retry if the reset reason is overflow).
   470→  if (reset_reason == Http::StreamResetReason::Overflow) {
   471→    return RetryDecision::NoRetry;
   472→  }
   473→
   474→  if (reset_reason == Http::StreamResetReason::LocalConnectionFailure ||
   475→      reset_reason == Http::StreamResetReason::RemoteConnectionFailure ||
   476→      reset_reason == Http::StreamResetReason::ConnectionTimeout) {
   477→    if (http3_used != Http3Used::Unknown && clusterSupportsHttp3AndTcpFallback(cluster_)) {
   478→      // Already got request encoder, so this must be a 0-RTT handshake failure. Retry
   479→      // immediately.
   480→      // TODO(danzh) consider making the retry configurable.
   481→      ASSERT(http3_used == Http3Used::Yes,
   482→             "0-RTT was attempted on non-Quic connection and failed.");
   483→      return RetryDecision::RetryImmediately;
   484→    }
   485→    if (retry_on_ & RetryPolicy::RETRY_ON_CONNECT_FAILURE) {
   486→      // This is a pool failure.
   487→      return RetryDecision::RetryWithBackoff;
   488→    }
   489→  } else if (http3_used == Http3Used::Yes && clusterSupportsHttp3AndTcpFallback(cluster_) &&
   490→             (retry_on_ & RetryPolicy::RETRY_ON_HTTP3_POST_CONNECT_FAILURE)) {
   491→    // Retry any post-handshake failure immediately with http3 disabled if the
   492→    // failed request was sent over Http/3.
   493→    disable_http3 = true;
   494→    return RetryDecision::RetryImmediately;
   495→  }
   496→
   497→  // Technically, this doesn't *have* to go before the RETRY_ON_RESET check,
   498→  // but it's safer for the user if they have them both set
   499→  // for some reason.
   500→  if (retry_on_ & RetryPolicy::RETRY_ON_RESET_BEFORE_REQUEST && !upstream_request_started) {
   501→    // Only return a positive retry decision if we haven't sent any bytes upstream.
   502→    return RetryDecision::RetryWithBackoff;
   503→  }
   504→
   505→  if (retry_on_ & RetryPolicy::RETRY_ON_RESET) {
   506→    return RetryDecision::RetryWithBackoff;
   507→  }
   508→
   509→  if (retry_on_ & (RetryPolicy::RETRY_ON_5XX | RetryPolicy::RETRY_ON_GATEWAY_ERROR)) {
   510→    // Currently we count an upstream reset as a "5xx" (since it will result in
   511→    // one). With RETRY_ON_RESET we may eventually remove these policies.
   512→    return RetryDecision::RetryWithBackoff;
   513→  }
   514→
   515→  if ((retry_on_ & RetryPolicy::RETRY_ON_REFUSED_STREAM) &&
   516→      reset_reason == Http::StreamResetReason::RemoteRefusedStreamReset) {
   517→    return RetryDecision::RetryWithBackoff;
   518→  }
   519→
   520→  return RetryDecision::NoRetry;
   521→}
   522→
   523→} // namespace Router
   524→} // namespace Envoy
